const stdout = $input.first().json.stdout || '';
const lines = stdout.trim().split('\n');
try {
  const plan = JSON.parse(lines[lines.length - 1]);
  const result = { ...plan, run_id: $('Set Defaults').first().json.run_id };
  return [{ json: result }];
} catch (e) { throw new Error('Parse plan failed: ' + e.message); }

// Mattermost sends POST with {context: {action, gate, run_id, ...}}
// Also support query params for GET fallback
const input = $input.first().json;
const ctx = input.context || input.body?.context || input.query || input;
return [{ json: {
  gate: parseInt(ctx.gate ?? '0'),
  run_id: ctx.run_id || '',
  action: ctx.action || 'approve'
}}];

